import{Q as a}from"./QExpansionItem.fe8a8290.js";import{Q as n,a as l,b as i,c as r}from"./QPage.18745d3f.js";import{E as d}from"./EssentialLink.3c8ca325.js";import{_ as c,o as u,c as h,w as t,r as p,U as e,a as o}from"./index.8919de57.js";import"./QItem.cc121638.js";import"./use-dark.4f9a2ad6.js";import"./uid.42677368.js";import"./QResizeObserver.845aca48.js";const m={name:"PersonalTools",components:{EssentialLink:d}},g={class:"row"},f={class:"col-6"},w=e("p",null," Obsidian is a smart Markdown editor that allows you to use internal note links. ",-1),y=e("p",null,` Marketed as a "second brain" or knowledge base, it's not unlike other software like Notion. `,-1),_=e("p",null," What I really enjoy about Obsidian, though, is its customisability and flexibility through community plugins. ",-1),k=e("p",null," You can add plugins for just about anything, from custom templating, calendars, code syntax highlighting and Git integration. ",-1),b=e("p",null," Additionally, the files are saved and organised as plain Markdown files inside plain folders, meaning you can open/edit them with other software, and keep all your files even in the case of Obsidian deprecation. I.e., it's future proof! ",-1),v=e("p",null," VS Code is my editor of choice. ",-1),x=e("p",null," Extensibility, customisation, and an active community are important factors. ",-1),T=e("p",null," VS Code also allows you to integrate your habitual workflow, through specific keybindings (like JetBrains bindings) or emulators (like a Vim emulator). ",-1),L=e("p",null," LaTeX is a clever document format that allows you to insert special symbols, format your text, and add citations and references easily. It's kind of like a programming language, but the output is a text document. ",-1),I=e("p",null," To edit LaTeX files, I prefer to work with desktop environment and local files first, and then synchronise them with online editors like Overleaf. ",-1),X=e("p",null," Therefore, I use TeX Live with the LaTeX Workshop extension in VS Code to edit my LaTeX files. ",-1),C=e("p",null," This is also handy because I can set up Overleaf integration using GitHub if I'm collaborating or want to share my files. ",-1),S=e("p",null," TeX Live is a full TeX system containing the major programs, packages, etc. that you need to work with TeX files locally on your computer. It's open-source, regularly maintained, and available on Windows, macOS and most Linux distros. ",-1),W=e("p",null," LaTeX Workshop lets you build your LaTeX files and preview them live inside VS Code. I usually use the PDF preview side-by-side with my source code while writing. ",-1),E=e("p",null," I use Google Calendar as the central hub for all my other calendar applications, synchronising my calendars across platforms. ",-1),O=e("p",null," It's not optimal to grant Google access to even more of my information, but at least I never miss a meeting. ",-1),P=e("p",null," Additionally, I'm currently using the Morgen app. I like the aesthetic choices the team has made, its light customisability, and a global hotkey (alt+C by default) to show/hide the app. It's available on Windows, macOS, and all major Linux distros. ",-1),V=e("p",null," This last one is for those of us running Windows on our computer, and wishing it was as easy as using Linux. ",-1),B=e("p",null," The most noticable difference in my workflow was in launching programs and searching for files on Windows. If you've used Linux, you know the Windows start menu just doesn't cut it. ",-1),M=e("p",null," PowerToys is a utility bundle from Microsoft themselves and contains many functions you may not use. However, its file launching feature, PowerToys Run, is worth checking out. It's like launching using the Super key, or using the macOS Spotlight. I also like the Color Picker utility. ",-1),Q=e("p",null," I also prefer it over alternative tools like FlowLauncher (non-optimal search results) and ueli (moves around when custom scaling is enabled). ",-1),G=e("p",null," When it comes to searching, though, you may need something even more thorough. That's where voidtools' Everything comes in. Like its name implies, it allows you to search for everything on your machine. And it's fast! ",-1);function j(N,$,A,F,H,J){const s=p("EssentialLink");return u(),h(n,{padding:""},{default:t(()=>[e("div",g,[e("div",f,[o(a,{class:"expansion-wrapper","switch-toggle-side":"","expand-separator":"","default-opened":"","header-class":"expansion-header",label:"Obsidian"},{default:t(()=>[w,y,_,k,b,o(s,{class:"link",title:"Obsidian",link:"https://obsidian.md/"})]),_:1}),o(a,{class:"expansion-wrapper","switch-toggle-side":"","expand-separator":"","default-opened":"","header-class":"expansion-header",label:"VS Code"},{default:t(()=>[v,x,T,o(s,{class:"link",title:"VS Code",link:"https://code.visualstudio.com/"})]),_:1}),o(a,{class:"expansion-wrapper","switch-toggle-side":"","expand-separator":"","default-opened":"","header-class":"expansion-header",label:"TeX Live & LaTeX Workshop"},{default:t(()=>[L,I,X,C,S,W,o(s,{class:"link",title:"TeX Live",link:"https://www.tug.org/texlive/"}),o(s,{class:"link",title:"LaTeX Workshop",link:"https://marketplace.visualstudio.com/items?itemName=James-Yu.latex-workshop"})]),_:1}),o(a,{class:"expansion-wrapper","switch-toggle-side":"","expand-separator":"","default-opened":"","header-class":"expansion-header",label:"Google Calendar & Morgen"},{default:t(()=>[E,O,P,o(s,{class:"link",title:"Google Calendar",link:"https://calendar.google.com/"}),o(s,{class:"link",title:"Morgen",link:"https://www.morgen.so/"})]),_:1}),o(a,{class:"expansion-wrapper","switch-toggle-side":"","expand-separator":"","default-opened":"","header-class":"expansion-header",label:"PowerToys & Everything"},{default:t(()=>[V,B,M,Q,G,o(s,{class:"link",title:"PowerToys",link:"https://learn.microsoft.com/en-us/windows/powertoys/"}),o(s,{class:"link",title:"Everything",link:"https://www.voidtools.com/"})]),_:1})])]),o(r,{class:"row footer"},{default:t(()=>[o(l,{class:"code-text"},{default:t(()=>[o(i,{class:"inactive-label",label:"~"}),o(i,{class:"inactive-label",label:"Sophie Bosio",to:"/"}),o(i,{class:"inactive-label",label:"personal",to:"/personal"}),o(i,{label:"tools",to:"/personal/tools"})]),_:1})]),_:1})]),_:1})}var ee=c(m,[["render",j]]);export{ee as default};
